import { formatUserError } from '@/lib/errors';
import { setAuthCookie, clearAuthCookie } from '@/lib/auth-session';

interface LoginRequest {
  email: string;
  password: string;
}

interface LoginResponse {
  accessToken: string;
  agencyId: string;
  tenantId: string;
  userId: string;
  displayName: string;
}

const DEMO_EMAIL = 'admin@rapidexpress.cm';
const DEMO_PASSWORD = 'demo1234';

function persistSession(result: LoginResponse): void {
  localStorage.setItem('tnt-token', result.accessToken);
  localStorage.setItem('tnt-tenant-id', result.tenantId);
  localStorage.setItem('tnt-agency-id', result.agencyId);
  localStorage.setItem('tnt-user-id', result.userId);
  setAuthCookie(result.accessToken);
}

export const authService = {
  async login(credentials: LoginRequest): Promise<LoginResponse> {
    if (DEMO_MODE) {
      await new Promise(r => setTimeout(r, 800));
      if (
        credentials.email === DEMO_EMAIL &&
        credentials.password === DEMO_PASSWORD
      ) {
        const result: LoginResponse = {
          accessToken: 'demo-jwt-token-rapid-express',
          agencyId: DEMO_AGENCY_ID,
          tenantId: DEMO_TENANT_ID,
          userId: DEMO_USER_ID,
          displayName: 'Rapid Express Douala',
        };
        persistSession(result);
        return result;
      }
      throw new Error('Identifiants incorrects. Essayez admin@rapidexpress.cm / demo1234');
    }

    const res = await fetch(`${API_BASE_URL}/auth/login`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-Tenant-Id': DEMO_TENANT_ID,
      },
      body: JSON.stringify({
        email: credentials.email,
        password: credentials.password,
        tenantId: DEMO_TENANT_ID,
        agencyId: DEMO_AGENCY_ID,
      }),
    });

    if (!res.ok) {
      const body = await res.json().catch(() => ({}));
      throw new Error(body?.message ?? 'Identifiants incorrects');
    }

    const data = await res.json() as {
      accessToken: string;
      tenantId: string;
      agencyId: string;
      userId: string;
      email: string;
    };

    const result: LoginResponse = {
      accessToken: data.accessToken,
      agencyId: data.agencyId,
      tenantId: data.tenantId,
      userId: data.userId,
      displayName: data.email,
    };
    persistSession(result);
    return result;
  },

  logout(): void {
    localStorage.removeItem('tnt-token');
    localStorage.removeItem('tnt-tenant-id');
    localStorage.removeItem('tnt-agency-id');
    localStorage.removeItem('tnt-user-id');
    clearAuthCookie();
    if (typeof window !== 'undefined') {
      window.location.href = '/login';
    }
  },

  isAuthenticated(): boolean {
    if (typeof window === 'undefined') return false;
    return !!localStorage.getItem('tnt-token');
  },
};
